/* 1. ID: selectList 2. 업무명: 관리자의 리스트 3. 업무설명: */ SELECT * FROM ( SELECT store_id ,party_cd ,bis_num ,store_cell_num ,store_ceo_nm ,store_nm ,store_img ,store_addr ,store_event ,IF(store_event is NULL, '할인 없음', concat(store_event, '00원 할인')) store_event_txt ,store_kakao_id ,store_latitude ,store_longitude from CRBN_STORE_INFO where party_cd = #{partyCd} and store_stat = 'V'
and store_nm like CONCAT('%',#{storeNm},'%')
ORDER BY store_nm ) A LIMIT #{pageNo}, #{listSize}

mapper.insert:

            /*
                1. ID: insert
                2. 업무명: 뉴스
                3. 업무설명: 뉴스 등록
            */
            INSERT INTO CRBN_STORE_INFO (
			   store_id
			  ,party_cd
			  ,bis_num
			  ,store_pwd
			  ,store_cell_num
			  ,store_ceo_nm
			  ,store_nm

			  ,store_latitude
			  ,store_longitude

			  ,store_no_img
			  ,store_img
			  ,store_email
			  ,store_addr
			  ,store_event
			  ,cre_dtm
			  ,chg_dtm

            ) VALUES (
			    concat('S',carbonbankDB.NEXTVAL('STORE'))
			  , #{partyCd}
			  , #{bisNum}
			  , ' '
			  , #{storeCellNum}
			  , #{storeCeoNm}
			  , #{storeNm}

			  , #{storeLatitude}
			  , #{storeLongitude}

			  , #{storeNoImg}
			  , #{storeImg}
			  , #{storeEmail}
			  , #{storeAddr}
			  , #{storeEvent}
			  , now()
			  , now()

            )
